import { useEffect, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;

function normalizeList(d){ return Array.isArray(d) ? {list:d,pages:1} : {list:d?.content||[], pages:d?.totalPages||1}; }
const ROLES = ["ADMIN","SALES","ACCOUNTANT"];
const STATUSES = ["ACTIVE","INACTIVE"];
const DEPTS = ["Kinh doanh","Kế toán","Hành chính","Kỹ thuật"];

export default function Users(){
    const [rows,setRows]=useState([]);
    const [page,setPage]=useState(0);
    const [totalPages,setTotalPages]=useState(1);
    const [loading,setLoading]=useState(true);

    const [show,setShow]=useState(false);
    const [editing,setEditing]=useState(null);
    const [form,setForm]=useState({
        username:"", email:"", phone:"", dept:"Kinh doanh", note:"",
        role:"SALES", status:"ACTIVE"
    });

    useEffect(()=>{ load(); },[page]);

    async function load(){
        setLoading(true);
        try{
            const {data}=await api.get("/api/users",{params:{page,size:PAGE_SIZE,sort:"id,desc"}});
            const {list,pages}=normalizeList(data);
            // nắn các field đề phòng backend khác key
            setRows(list.map(u=>({
                id: u.id,
                username: u.username || u.name,
                email: u.email,
                phone: u.phone || u.mobile,
                dept: u.dept || u.department,
                note: u.note || u.remark,
                role: (u.role || u.roles?.[0] || "SALES").replace(/^ROLE_/,""),
                status: u.status || (u.enabled===false ? "INACTIVE":"ACTIVE"),
            })));
            setTotalPages(pages);
        }catch(e){ console.error(e); setRows([]); setTotalPages(1); }
        finally{ setLoading(false); }
    }

    function openCreate(){
        setEditing(null);
        setForm({username:"", email:"", phone:"", dept:"Kinh doanh", note:"", role:"SALES", status:"ACTIVE"});
        setShow(true);
    }
    function openEdit(row){
        setEditing(row);
        setForm({...row});
        setShow(true);
    }

    async function save(e){
        e.preventDefault();
        const payload={
            username: form.username,
            email: form.email,
            phone: form.phone,
            dept: form.dept,
            note: form.note,
            role: form.role,        // nếu backend cần "roles": ["ROLE_ADMIN"] => map sang tại đây
            status: form.status
        };
        try{
            if(editing) await api.put(`/api/users/${editing.id}`, payload);
            else        await api.post("/api/users", payload);
            setShow(false); await load();
        }catch(err){ alert(err?.response?.data?.message || "Lưu người dùng thất bại"); }
    }
    async function remove(row){
        if(!window.confirm(`Xoá người dùng ${row.username}?`)) return;
        try{ await api.delete(`/api/users/${row.id}`); await load(); }
        catch(err){ alert(err?.response?.data?.message || "Xoá người dùng thất bại"); }
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                    <p className="text-sm text-slate-500">Quản trị viên có thể quản lý người dùng</p>
                </div>
                <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Thêm người dùng</button>
            </div>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Vai trò</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Đang tải…</td></tr>
                        ) : rows.length===0 ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Chưa có dữ liệu</td></tr>
                        ) : rows.map(u=>(
                            <tr key={u.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{u.username}</td>
                                <td className="px-4 py-3">{u.email}</td>
                                <td className="px-4 py-3">{u.phone || "-"}</td>
                                <td className="px-4 py-3">{u.dept || "-"}</td>
                                <td className="px-4 py-3">{u.role}</td>
                                <td className="px-4 py-3">
                    <span className={"px-2 py-0.5 rounded-full text-xs "+(u.status==="ACTIVE"?"bg-emerald-100 text-emerald-700":"bg-slate-100 text-slate-700")}>
                      {u.status}
                    </span>
                                </td>
                                <td className="px-4 py-3 text-right">
                                    <div className="inline-flex gap-2">
                                        <button onClick={()=>openEdit(u)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                        <button onClick={()=>remove(u)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage(p=>Math.max(0,p-1))} disabled={page<=0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page+1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage(p=>p+1)} disabled={page+1>=totalPages}>Sau →</button>
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing?"Sửa người dùng":"Thêm người dùng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={()=>setShow(false)}>Đóng</button>
                        </div>
                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Tên</label>
                                <input required value={form.username} onChange={e=>setForm(f=>({...f,username:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input required type="email" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input value={form.phone} onChange={e=>setForm(f=>({...f,phone:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Vai trò</label>
                                <select value={form.role} onChange={e=>setForm(f=>({...f,role:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {ROLES.map(r=><option key={r}>{r}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {STATUSES.map(s=><option key={s}>{s}</option>)}
                                </select>
                            </div>
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Ghi chú nội bộ</label>
                                <input value={form.note} onChange={e=>setForm(f=>({...f,note:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={()=>setShow(false)}>Huỷ</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
